script.inlineScript:
import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const question = input.question || 'No question provided';
  writeFileSync('/output/presentation.md', `## Question from your Product Owner\n\n${question}\n\nPlease share your perspective below.`);
  writeFileSync('/output/result.json', JSON.stringify({ question }));
  console.log('Question rendered for presentation');
} catch (err) {
  console.error('show_question crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}
